        "jsCode": "const input = $input.first().json;\n\nconst llmContent = input.message?.content ?? input.content ?? input;\nlet spec;\nif (typeof llmContent === 'string') {\n  try {\n    spec = JSON.parse(\n      String(llmContent)\n        .replace(/^```json\\s*/i, '')\n        .replace(/```\\s*$/i, '')\n        .trim()\n    );\n  } catch (e) {\n    spec = { prompt: String(llmContent), _parse_error: e.message };\n  }\n} else {\n  spec = llmContent || {};\n}\n\nconst CTX_NODE_NAME = 'Build Final Context5';\n\nlet ctx = {};\ntry {\n  ctx = $(CTX_NODE_NAME).first().json || {};\n} catch (e) {\n  ctx = {};\n}\n\nconst sheet = ctx._sheet_row || ctx || {};\n// UPDATE: đọc Prompt Update từ context (chỉ có giá trị khi đúng là vòng retry),\n// tránh inject nhầm revision note cũ còn lưu trên Sheet ở lần generate đầu\nconst updatePrompt = ctx.prompt_update || 'Không có';\n\nconst isHttp = (s) => typeof s === 'string' && /^https?:\\/\\//i.test(s.trim());\n\nconst findImageByRole = (role) =>\n  (spec.input_images || []).find((i) => i.role === role)?.url || '';\n\nconst firstHttp = (cands) => {\n  for (const [k, v] of Object.entries(cands)) {\n    const val = String(v || '').trim();\n    if (isHttp(val)) return { url: val, source: k };\n  }\n  return { url: '', source: 'none' };\n};\n\nconst pickFromSheet = (...keys) => {\n  for (const k of keys) {\n    const v = sheet?.[k];\n    if (v != null && String(v).trim() !== '') return String(v).trim();\n  }\n  return '';\n};\n\nconst refCandidates = {\n  'ctx.ref_image_url':               ctx.ref_image_url || '',\n  'spec.input_images[ref_role]':     findImageByRole('reference_style_composition'),\n  'spec.reference_image_url':        spec.reference_image_url || '',\n  'sheet[Link Ref Image 1]':         sheet['Link Ref Image 1'] || '',\n  'sheet[Link Ref Image 2]':         sheet['Link Ref Image 2'] || '',\n  'sheet[Link Ref Image (origin)]':  sheet['Link Ref Image (origin)'] || ''\n};\n\nconst productCandidates = {\n  'ctx.product_image_url':        ctx.product_image_url || '',\n  'spec.input_images[prod_role]': findImageByRole('product_to_feature'),\n  'spec.product_image_url':       spec.product_image_url || '',\n  'sheet[Product Generate]':      sheet['Product Generate'] || ''\n};\n\nlet { url: refImageUrl,     source: refSource }     = firstHttp(refCandidates);\nlet { url: productImageUrl, source: productSource } = firstHttp(productCandidates);\n\nconst PLACEHOLDER_URL = 'https://placehold.co/1024x1024.png';\nlet skipGeneration = false;\n\nif (!refImageUrl && productImageUrl) {\n  refImageUrl = productImageUrl;\n  refSource = 'fallback:product_image_url';\n}\nif (!productImageUrl && refImageUrl) {\n  productImageUrl = refImageUrl;\n  productSource = 'fallback:ref_image_url';\n}\nif (!refImageUrl && !productImageUrl) {\n  refImageUrl = PLACEHOLDER_URL;\n  productImageUrl = PLACEHOLDER_URL;\n  refSource = 'fallback:placeholder';\n  productSource = 'fallback:placeholder';\n  skipGeneration = true;\n}\n\nif (!isHttp(refImageUrl))     refImageUrl     = PLACEHOLDER_URL;\nif (!isHttp(productImageUrl)) productImageUrl = PLACEHOLDER_URL;\n\nconst websiteFromCtx   = String(ctx.brand_website_url || '').trim();\nconst websiteFromSheet = pickFromSheet(\n  'Link Website',\n  'Website',\n  'Brand Website',\n  'Website URL',\n  'Link website',\n  'link website',\n  'Brand Website URL',\n  'Link Web'\n);\nconst brandWebsiteUrl = websiteFromCtx || websiteFromSheet || '';\n\nconst hardRules = [\n  '╔══════════════════════════════════════════════════════════════╗',\n  '║   COMPOSITE TASK — DO NOT GENERATE FROM SCRATCH               ║',\n  '║   Product = pixel-perfect paste. Scene = creative from Brief. ║',\n  '╚══════════════════════════════════════════════════════════════╝',\n  '',\n  'TWO inline images are attached IN THIS ORDER:',\n  '  • inline_data #1  =  IMAGE 1  =  TECHNICAL REFERENCE ONLY',\n  '       → Use ONLY for: camera angle, lens compression, framing tightness,',\n  '         lighting direction, shadow quality, color temperature, mood/feel.',\n  '       → DO NOT copy its scene, background, person, outfit, props,',\n  '         environment, or any literal content.',\n  '',\n  '  • inline_data #2  =  IMAGE 2  =  THE ACTUAL PRODUCT (PASTE-IN)',\n  '       → Treat as a FIXED PNG cutout. INSERT it into the new scene UNCHANGED.',\n  '       → MUST preserve pixel-perfect: container shape, transparency,',\n  '         ALL printed label text, logo placement and color, drink color layers,',\n  '         foam, toppings, garnish, ice density, condensation, opacity, proportions.',\n  '       → DO NOT redraw, restyle, recolor, smooth, beautify, illustrate.',\n  '',\n  '━━━ CREATIVE ELEVATION (mục tiêu: ảnh đẳng cấp campaign quảng cáo) ━━━',\n  '  • Pick the creative mode that fits the Brief/Content/Pillar:',\n  '      MODE A — BOLD KEY VISUAL: hero-scale product (40-60% of frame), levitating',\n  '        flavor-true ingredients, frozen-motion splashes, suspended ice cubes,',\n  '        dramatic sky / sunburst / surreal landscape backdrop,',\n  '        CGI-grade photorealism of a top-tier beverage campaign poster.',\n  '      MODE B — CINEMATIC LIFESTYLE: real environment, human warmth, layered',\n  '        foreground/midground/background depth, golden-hour or moody light,',\n  '        film-stock grade, candid editorial energy.',\n  '  • Define composition geometry: product position & scale in frame, depth layers,',\n  '    leading lines guiding the eye to the product.',\n  '  • Reserve ONE clean negative-space area (top third or one side, simple background)',\n  '    for typography that designers will add in post — the image itself stays text-free.',\n  '  • Atmosphere FX allowed only if physics-real and true to THIS product:',\n  '    splash arcs, droplets, condensation, steam, flying garnish, ice shatter.',\n  '  • Color story must anchor to the brand palette and the product dominant HEX colors.',\n  '',\n  '━━━ NO TEXT POLICY ━━━',\n  '  • Zero captions, headline