      full_prompt_variant: variantPrompt,
      aspect_ratio:        aspectRatio,
      ref_mime:            refMime,
      product_mime:        productMime,
      gemini_body:         buildBody(basePrompt),
      gemini_body_variant: buildBody(variantPrompt)
    }
  }
