// fallback về node Prep Gemini Input1 vì HTTP Request (file response) có thể không passthrough json
let ctx = {};
try {
  ctx = $('Prep Gemini Input1').first().json || {};
} catch (e) {
  ctx = {};
}

if (ctx._skip_generation) {
  return [{ json: { _skipped: true, reason: 'No valid ref/product image URL — generation skipped.' } }];
}

if (!item.binary?.ref_image) {
  throw new Error("Missing binary ref_image");
}

if (!item.binary?.product_image) {
  throw new Error("Missing binary product_image");
}

const refBuffer = await this.helpers.getBinaryDataBuffer(0, "ref_image");
const productBuffer = await this.helpers.getBinaryDataBuffer(0, "product_image");

const basePrompt    = item.json.full_prompt_text    || ctx.full_prompt_text    || "";
const variantPrompt = item.json.full_prompt_variant || ctx.full_prompt_variant || basePrompt;
const aspectRatio   = item.json.aspect_ratio        || ctx.aspect_ratio        || "1:1";

const refMime     = item.binary.ref_image.mimeType     || "image/jpeg";
const productMime = item.binary.product_image.mimeType || "image/png";

const refB64     = refBuffer.toString("base64");
const productB64 = productBuffer.toString("base64");

const buildBody = (promptText) => ({
  contents: [
    {
      role: "user",
      parts: [
        { text: promptText },
        { inline_data: { mime_type: refMime,     data: refB64 } },
        { inline_data: { mime_type: productMime, data: productB64 } }
      ]
    }
  ],
  generationConfig: {
    candidateCount: 1,
    responseModalities: ["TEXT", "IMAGE"],
    imageConfig: { aspectRatio: aspectRatio }
  }
});

return [
  {
    json: {
      full_prompt_text:    basePrompt,
      full_prompt_variant: variantPrompt,
      aspect_ratio:        aspectRatio,
      ref_mime:            refMime,
      product_mime:        productMime,
      gemini_body:         buildBody(basePrompt),
      gemini_body_variant: buildBody(variantPrompt)
    }
  }
];"
